import React, { Component } from 'react';
import { Markup } from 'interweave';
import nl2br from 'react-newline-to-break'; 


const MedCap = 14
const icuCap = 6
const step2CensusOct = 10, step2CensusResiternOct = 8, step2TotalAdmitAllowOct = 2
const step4CensusOct = 12, step4CensusResiternOct = 10, step4TotalAdmitAllowOct = 2
const step12Census = 14, step12TotalAdmitAllow =3
const step2Census = 8, step2TotalAdmitAllow = 2
const step3Census = 12, step3TotalAdmitAllow = 2
const step4Census = 14, step4TotalAdmitAllow = 1
var step51Census = 5
const step51TotalAdmitAllow= 1, step51TotalPatientAllow = 10
const step52Total = 9, step52TotalAdmitAllow = 1
const step53Total = 5, step53TotalAdmitAllow = 3, step53TotalPostPost = 7, step53TotalPostPostResiternOff = 6
const step54Total = 8, step54TotalAdmitAllow = 2
const step55Census = 14, step55CensusResitern = 12, step55TotalAdmitAllow = 2
const step56Total = 5, step56TotalAdmitAllow = 3
const step57Total = 9, step57TotalAdmitAllow = 1
const step58Census = 14, step58TotalAdmitAllow = 2
const step59Census = 10, step59TotalAdmitAllow = 2
const step510Total = 6, step510TotalAdmitAllow = 3
const step511Census = 14, step511TotalAdmitAllow = 2

function dynamicSort(property) {
  var sortOrder = 1;
  if(property[0] === "-") {
      sortOrder = -1;
      property = property.substr(1);
  }
  return function (a,b) {
      /* next line works with strings and numbers, 
       * and you may want to customize it to your needs
       */
      var result = (a[property] < b[property]) ? -1 : (a[property] > b[property]) ? 1 : 0;
      return result * sortOrder;
  }
}

function dynamicDescSort(property) {
  var sortOrder = 1;
  if(property[0] === "-") {
      sortOrder = -1;
      property = property.substr(1);
  }
  return function (a,b) {
      /* next line works with strings and numbers, 
       * and you may want to customize it to your needs
       */
      var result = (a[property] > b[property]) ? -1 : (a[property] < b[property]) ? 1 : 0;
      return result * sortOrder;
  }
}





var signOutTeam = [];
var alreadySearch = [];
var globalSignoutTeamTime = [];

class CyberRaptorV2 extends Component {

    constructor(props) {
        super(props);
        this.state = { ICUBound: [], ICUStable: [], LateIncomplete: [], emailHeader: "", afterRun: false, assigned: [], middleRun: false, howManyGoldman: 0, remainPatients: [],
        icuStableRemainPatients: [], icuBoundRemainPatients: [], lateIncompleteRemainPatients: [],
        signoutTime: "", emailHeader: "", emailFooter: "", badgerRoom: "", wolfRoom: "", hawkRoom: "", eagleRoom: "", owlRoom: ""
        };
      }

      createSelectItems() {
        let items = [];         
        for (var key in this.props.patients) {
          if (!this.props.patients[key].name.includes("ROUNDING") && this.props.patients[key].patients.length > 0) {
              this.props.patients[key].patients.map(Record => (items.push(<option key={Record.PatientID.filter(A => A.PatientIDType.includes("MRN"))[0].PatientID} value={Record.PatientID.filter(A => A.PatientIDType.includes("MRN"))[0].PatientID}>{Record.Name},{Record.Age},{Record.Sex}</option>)))
          }
      }
        return items;
    }  

    /*
    sortTotalPatient = (a, b) => {
      var assignmentA = a.totalPts
      var assignmentB = b.totalPts
      if (assignmentA > assignmentB) {
        return -1;
      }
      if (assignmentA < assignmentB) {
        return 1;
      }
      // assignment must be equal
      return 0;
    }
*/

sortTeamTimeAsc = (a, b) => {
  var timeA = new Date('1970-01-01T' + this.toggle24hr(a.startTime) + ":00")
  var timeB = new Date('1970-01-01T' + this.toggle24hr(b.startTime) + ":00")

  if (timeA > timeB) {
    return 1;
  }
  if (timeA < timeB) {
    return -1;
  }
  // assignment must be equal
  return 0;
}

sortTeamTimeDesc = (a, b) => {
  var timeA = new Date('1970-01-01T' + this.toggle24hr(a.startTime) + ":00")
  var timeB = new Date('1970-01-01T' + this.toggle24hr(b.startTime) + ":00")

  if (timeA > timeB) {
    return -1;
  }
  if (timeA < timeB) {
    return 1;
  }
  // assignment must be equal
  return 0;
}


   onDropdownSelected(e) {
       //console.log("THE VAL", e.target.value);
       //here you will see the current selected value of the select input
   }


   onAddICUBound = () => {
    // not allowed AND not working
    var e = document.getElementById("ICUBound");
    var patient = {}

    for (var key in this.props.patients) {        
      for (var j in this.props.patients[key].patients) {
        if (this.props.patients[key].patients[j].MRN === e.options[e.selectedIndex].value) {
          patient = {Covid: this.props.patients[key].patients[j].COVID, Team: this.props.patients[key].name, MRN: this.props.patients[key].patients[j].MRN, CSN: this.props.patients[key].patients[j].CSN, OneLiner: this.props.patients[key].patients[j].OneLiner, Name: this.props.patients[key].patients[j].Name, Age: this.props.patients[key].patients[j].Age, Location: this.props.patients[key].patients[j].Location, Sex: this.props.patients[key].patients[j].Sex}
        }
      }
    }

    if (this.state.ICUBound.filter(Record => Record.MRN ===e.options[e.selectedIndex].value).length > 0){
      alert("Already added");
      return
    }

    if (this.state.ICUStable.filter(Record => Record.MRN ===e.options[e.selectedIndex].value).length > 0){
      alert("Already added in ICU Stable");
      return
    }

    if (this.state.LateIncomplete.filter(Record => Record.MRN ===e.options[e.selectedIndex].value).length > 0){
      alert("Already added in late/incomplete admits");
      return
    }

    let icuBound = this.state.ICUBound;
    icuBound.push(patient)
    this.setState({ICUBound: icuBound});
  };

  onRemoveICUBound = (evt) => {
    let icuBound = this.state.ICUBound;
    var i = icuBound.findIndex(patient => patient.MRN === evt.currentTarget.value)
    if (i => 0) {
      icuBound.splice(i, 1)
    }
    this.setState({ICUBound: icuBound})
  }

  onRemoveICUStable = (evt) => {
    let icuStable = this.state.ICUStable;
    var i = icuStable.findIndex(patient => patient.MRN === evt.currentTarget.value)
    if (i => 0) {
      icuStable.splice(i, 1)
    }
    this.setState({ICUStable: icuStable})
  }

  onRemoveICUStable = (evt) => {
    let icuStable = this.state.ICUStable;
    var i = icuStable.findIndex(patient => patient.MRN === evt.currentTarget.value)
    if (i => 0) {
      icuStable.splice(i, 1)
    }
    this.setState({ICUStable: icuStable})
  }

  onRemoveLateIncomplete = (evt) => {
    let lateIncomplete = this.state.LateIncomplete;
    var i = lateIncomplete.findIndex(patient => patient.MRN === evt.currentTarget.value)
    if (i => 0) {
      lateIncomplete.splice(i, 1)
    }
    this.setState({LateIncomplete: lateIncomplete})
  }


  onAddLateIncomplete = () => {
      // not allowed AND not working
      var e = document.getElementById("LateIncomplete");
      var patient = {}

      for (var key in this.props.patients) {        
        for (var j in this.props.patients[key].patients) {
          if (this.props.patients[key].patients[j].MRN === e.options[e.selectedIndex].value) {
            patient = {Covid: this.props.patients[key].patients[j].COVID, Team: this.props.patients[key].name, MRN: this.props.patients[key].patients[j].MRN, CSN: this.props.patients[key].patients[j].CSN, OneLiner: this.props.patients[key].patients[j].OneLiner, Name: this.props.patients[key].patients[j].Name, Age: this.props.patients[key].patients[j].Age, Location: this.props.patients[key].patients[j].Location, Sex: this.props.patients[key].patients[j].Sex}
          }
        }
      }

      if (this.state.LateIncomplete.filter(Record => Record.MRN ===e.options[e.selectedIndex].value).length > 0){
        alert("Already added");
        return
      }

      if (this.state.ICUBound.filter(Record => Record.MRN ===e.options[e.selectedIndex].value).length > 0){
        alert("Already added in ICU Bound");
        return
      }

      if (this.state.ICUStable.filter(Record => Record.MRN ===e.options[e.selectedIndex].value).length > 0){
        alert("Already added in ICU Stable");
        return
      }

      let lateIncomplete = this.state.LateIncomplete;
      lateIncomplete.push(patient)
      this.setState({LateIncomplete: lateIncomplete});
  }



  onAddICUStable = () => {
    // not allowed AND not working
    var e = document.getElementById("ICUStable");
    var patient = {}

    for (var key in this.props.patients) {        
      for (var j in this.props.patients[key].patients) {
        if (this.props.patients[key].patients[j].MRN === e.options[e.selectedIndex].value) {
          patient = {Covid: this.props.patients[key].patients[j].COVID, Team: this.props.patients[key].name, MRN: this.props.patients[key].patients[j].MRN, CSN: this.props.patients[key].patients[j].CSN, OneLiner: this.props.patients[key].patients[j].OneLiner, Name: this.props.patients[key].patients[j].Name, Age: this.props.patients[key].patients[j].Age, Location: this.props.patients[key].patients[j].Location, Sex: this.props.patients[key].patients[j].Sex}
        }
      }
    }

    if (this.state.ICUStable.filter(Record => Record.MRN ===e.options[e.selectedIndex].value).length > 0){
      alert("Already added");
      return
    }

    if (this.state.ICUBound.filter(Record => Record.MRN ===e.options[e.selectedIndex].value).length > 0){
      alert("Already added in ICU Bound");
      return
    }

    if (this.state.LateIncomplete.filter(Record => Record.MRN ===e.options[e.selectedIndex].value).length > 0){
      alert("Already added in late/incomplete admits");
      return
    }

    let icuStable = this.state.ICUStable;
    icuStable.push(patient)
    this.setState({ICUStable: icuStable});
  };

  handleEmailHeaderChange  = (event) => {
    this.setState({emailHeader: event.target.value});
  }

  findMinCensusAdmitTotalPatient = (team, census, admit, totalPatient) => {
    var teamIndex = -1
    var minPts = -1
    for(var g=0;g<team.length;g++) {
      if (team[g].TotalPts + team[g].Admit < census && team[g].Admit < admit && team[g].TotalPts < totalPatient) {
        if (teamIndex === -1 || team[g].TotalPts + team[g].Admit < minPts) {
          teamIndex = g
          minPts = team[g].TotalPts + team[g].Admit
        }
      }
    }
    return teamIndex;
  }

  findMinCensusAdmit = (team, census, admit) => {
    var teamIndex = -1
    var minPts = -1
    for(var g=0;g<team.length;g++) {
      if (team[g].TotalPts + team[g].Admit < census && team[g].Admit < admit) {
        if (teamIndex === -1 || team[g].TotalPts + team[g].Admit < minPts) {
          teamIndex = g
          minPts = team[g].TotalPts + team[g].Admit
        }
      }
    }
    return teamIndex;
  }

  findMinTotalAdmit = (team, total, admit) => {
    var teamIndex = -1
    var minPts = -1
    for(var g=0;g<team.length;g++) {
      if (team[g].TotalPts < total && team[g].Admit < admit) {
        if (teamIndex === -1 || team[g].TotalPts + team[g].Admit < minPts) {
          teamIndex = g
          minPts = team[g].TotalPts + team[g].Admit
        }
      }
    }
    return teamIndex;
  }

  findMinTotalEqualAdmit = (team, total, admit) => {
    var teamIndex = -1
    var minPts = -1
    for(var g=0;g<team.length;g++) {
      if (team[g].TotalPts === total && team[g].Admit < admit) {
        if (teamIndex === -1 || team[g].TotalPts + team[g].Admit < minPts) {
          teamIndex = g
          minPts = team[g].TotalPts + team[g].Admit
        }
      }
    }
    return teamIndex;
  }



  findMinTeam = (Team) => {
    return this.findMinTotalAdmit(Team, MedCap, icuCap)
  }


  findMinGoldmanTeam = (Team) => {
    var teamIndex = -1
    var minPts = -1
    var date = new Date(this.props.jsonData.today);
    var gsmTodayTeamNumber = date.getDay() + 1
    var gsmTodayTeamIndex = -1
    var gsmTodayTeamPts = -1
    var gsmTodayTeamAdmit = -1

    for(var g=0;g<Team.length;g++) {
      if (Team[g].Team.includes("#"+gsmTodayTeamNumber)) {
        gsmTodayTeamIndex = g
        gsmTodayTeamPts = Team[g].TotalPts
        gsmTodayTeamAdmit = Team[g].Admit
      } 
      if (Team[g].TotalPts + Team[g].Admit < step2Census && Team[g].Admit < step2TotalAdmitAllow) {
        if (teamIndex === -1 || Team[g].TotalPts < minPts) {
          teamIndex = g
          minPts = Team[g].TotalPts
        }
      }
    }

    if (gsmTodayTeamIndex != -1 && gsmTodayTeamPts === minPts && gsmTodayTeamAdmit < step2TotalAdmitAllow) {
      teamIndex = gsmTodayTeamIndex
    }

    return teamIndex;
  }

  runMove = (evt) => {
    var assigned = this.state.assigned

    for(var k=0;k<assigned.length;k++) {

      if (assigned[k].MRN === evt.currentTarget.value) {
        //alert(evt.currentTarget.value)
        //alert(document.getElementById("move_" + evt.currentTarget.value).value)
        assigned[k].Team = document.getElementById("move_" + evt.currentTarget.value).value
      }
    }
    //console.log(assigned)
    this.setState({assigned: assigned})
  }


  runMoveToAssign = (evt) => {
    var assigned = this.state.assigned
    var remainPatients = this.state.remainPatients
    var removeIndex = -1
    var stopLoop = false
    for (var i=0;i<remainPatients.length&&!stopLoop;i++) {
      if (remainPatients[i].MRN === evt.currentTarget.value){
        var assignPatient = {Covid: remainPatients[i].Covid, Type: "HO", Team: document.getElementById("move_" + remainPatients[i].MRN).value, FromTeam: remainPatients[i].Team, MRN: remainPatients[i].MRN, CSN: remainPatients[i].CSN, OneLiner: remainPatients[i].OneLiner, Name: remainPatients[i].Name, Age: remainPatients[i].Age, Location: remainPatients[i].Location, Sex: remainPatients[i].Sex}
        //console.log("****************")
        //console.log(assignPatient)
        assigned.push(assignPatient)
        removeIndex = i
        stopLoop = true
      }
    }
    if (removeIndex != -1)
      remainPatients.splice(removeIndex,1)
    this.setState({remainPatients: remainPatients})

    removeIndex = -1;
    stopLoop = false
    var icuStableRemainPatients = this.state.icuStableRemainPatients
    for (var i=0;i<icuStableRemainPatients.length&&!stopLoop;i++) {
      if (icuStableRemainPatients[i].MRN === evt.currentTarget.value){
        var assignPatient = {Type: "Stable", Team: document.getElementById("move_" + icuStableRemainPatients[i].MRN).value, FromTeam: icuStableRemainPatients[i].Team, MRN: icuStableRemainPatients[i].MRN, CSN: icuStableRemainPatients[i].CSN, OneLiner: icuStableRemainPatients[i].OneLiner, Name: icuStableRemainPatients[i].Name, Age: icuStableRemainPatients[i].Age, Location: icuStableRemainPatients[i].Location, Sex: icuStableRemainPatients[i].Sex}
        //console.log(assignPatient)
        assigned.push(assignPatient)
        removeIndex = i
        stopLoop = true
      }
    }
    if (removeIndex != -1)
      icuStableRemainPatients.splice(removeIndex,1)
    this.setState({icuStableRemainPatients: icuStableRemainPatients})

    removeIndex = -1;
    stopLoop = false
    var icuBoundRemainPatients = this.state.icuBoundRemainPatients
    for (var i=0;i<icuBoundRemainPatients.length&&!stopLoop;i++) {
      if (icuBoundRemainPatients[i].MRN === evt.currentTarget.value){
        var assignPatient = {Type: "Bound", Team: document.getElementById("move_" + icuBoundRemainPatients[i].MRN).value, FromTeam: icuBoundRemainPatients[i].Team, MRN: icuBoundRemainPatients[i].MRN, CSN: icuBoundRemainPatients[i].CSN, OneLiner: icuBoundRemainPatients[i].OneLiner, Name: icuBoundRemainPatients[i].Name, Age: icuBoundRemainPatients[i].Age, Location: icuBoundRemainPatients[i].Location, Sex: icuBoundRemainPatients[i].Sex}
        //console.log(assignPatient)
        assigned.push(assignPatient)
        removeIndex = i
        stopLoop = true
      }
    }
