  assignPatientToTeam = (team, icuStable, icuBound, lateIncomplete, remainPatients, assignedNumberPatientsPerTeam) => {

      for(var j=0;j<team.length;j++) {
        var numberOfStable = team[j].Stable
        var numberOfBound = team[j].Bound
        var numberOfRemain = team[j].Remain
        var numberOfLate = team[j].Late

        var totalNum = numberOfStable + numberOfBound + numberOfRemain + numberOfLate

        alreadySearch = [];

        while (totalNum > 0) {

          var foundTeam = this.findTeam(numberOfStable, numberOfBound, numberOfRemain, numberOfLate, icuStable, icuBound, lateIncomplete, remainPatients)

          if (numberOfStable > 0) {
            var returnObject = this.assignPatientByTeam(j,team,numberOfStable,icuStable, assignedNumberPatientsPerTeam,foundTeam,"Stable")
            numberOfStable = returnObject.numberOfRemain
            icuStable = returnObject.remainPatients
            assignedNumberPatientsPerTeam = returnObject.assignedNumberPatientsPerTeam
            alreadySearch.push({Team: foundTeam})
          }
          if (numberOfBound > 0) {
            var returnObject = this.assignPatientByTeam(j,team,numberOfBound,icuBound, assignedNumberPatientsPerTeam,foundTeam,"Bound")
            numberOfBound = returnObject.numberOfRemain
            icuBound = returnObject.remainPatients
            assignedNumberPatientsPerTeam = returnObject.assignedNumberPatientsPerTeam
            alreadySearch.push({Team: foundTeam})
          }
          if (numberOfLate > 0) {
            var returnObject = this.assignPatientByTeam(j,team,numberOfLate,lateIncomplete, assignedNumberPatientsPerTeam,foundTeam,"Late")
            numberOfLate = returnObject.numberOfRemain
            lateIncomplete = returnObject.remainPatients
            assignedNumberPatientsPerTeam = returnObject.assignedNumberPatientsPerTeam
            alreadySearch.push({Team: foundTeam})
          }
          //console.log(team[j])
          //console.log(JSON.stringify(remainPatients))
          //console.log(remainPatients.length)
          if (numberOfRemain > 0) {
            var returnObject = this.assignPatientByTeam(j,team,numberOfRemain,remainPatients, assignedNumberPatientsPerTeam,foundTeam,"HO")
            numberOfRemain = returnObject.numberOfRemain
            remainPatients = returnObject.remainPatients
            assignedNumberPatientsPerTeam = returnObject.assignedNumberPatientsPerTeam
            alreadySearch.push({Team: foundTeam})
          }
          //console.log(JSON.stringify(assignedNumberPatientsPerTeam))
          //console.log(JSON.stringify(remainPatients))
          //console.log(remainPatients.length)
          totalNum = numberOfStable + numberOfBound + numberOfRemain + numberOfLate
        }
      }

      return {icuStable: icuStable, icuBound: icuBound, lateIncomplete: lateIncomplete, remainPatients: remainPatients, assignedNumberPatientsPerTeam: assignedNumberPatientsPerTeam}
  }

  toggle24hr(time, onoff){
    if(onoff==undefined) onoff = isNaN(time.replace(':',''))//auto-detect format
    var pm = time.toString().toLowerCase().indexOf('pm')>-1 //check if 'pm' exists in the time string
    time = time.toString().toLowerCase().replace(/[ap]m/,'').split(':') //convert time to an array of numbers
    time[0] = Number(time[0])
    if(onoff){//convert to 24 hour:
        if((pm && time[0]!=12)) time[0] += 12
        else if(!pm && time[0]==12) time[0] = '00'  //handle midnight
        if(String(time[0]).length==1) time[0] = '0'+time[0] //add leading zeros if needed
    }else{ //convert to 12 hour:
        pm = time[0]>=12
        if(!time[0]) time[0]=12 //handle midnight
        else if(pm && time[0]!=12) time[0] -= 12
    }
    return onoff ? time.join(':').trim() : time.join(':')+(pm ? 'pm' : 'am')
}


